export const getGetRankingUrl = (params?: GetRankingParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/ranking?${stringifiedParams}` : `/api/ranking`
}

/**
 * @summary Get user ranking by points or weekly offers
 */
export const getRanking = async (params?: GetRankingParams, options?: RequestInit): Promise<UsuarioRanking[]> => {

  return customFetch<UsuarioRanking[]>(getGetRankingUrl(params),
  {
    ...options,
    method: 'GET'


  }
);}





export const getGetRankingQueryKey = (params?: GetRankingParams,) => {
    return [
    `/api/ranking`, ...(params ? [params] : [])
    ] as const;
    }


export const getGetRankingQueryOptions = <TData = Awaited<ReturnType<typeof getRanking>>, TError = ErrorType<unknown>>(params?: GetRankingParams, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getRanking>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getGetRankingQueryKey(params);



    const queryFn: QueryFunction<Awaited<ReturnType<typeof getRanking>>> = ({ signal }) => getRanking(params, { signal, ...requestOptions });





   return  { queryKey, queryFn, ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof getRanking>>, TError, TData> & { queryKey: QueryKey }
}

export type GetRankingQueryResult = NonNullable<Awaited<ReturnType<typeof getRanking>>>
export type GetRankingQueryError = ErrorType<unknown>


/**
 * @summary Get user ranking by points or weekly offers
 */

export function useGetRanking<TData = Awaited<ReturnType<typeof getRanking>>, TError = ErrorType<unknown>>(
 params?: GetRankingParams, options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getRanking>>, TError, TData>, request?: SecondParameter<typeof customFetch>}

 ):  UseQueryResult<TData, TError> & { queryKey: QueryKey } {

  const queryOptions = getGetRankingQueryOptions(params,options)

  const query = useQuery(queryOptions) as  UseQueryResult<TData, TError> & { queryKey: QueryKey };

  return { ...query, queryKey: queryOptions.queryKey };
}







